import json

def safe_json_parse(text, default=None):
    try:
        return json.loads(text)
    except (json.JSONDecodeError, TypeError):
        return default

def safe_get(data, keys, default=None):
    """Safely get nested value"""
    result = data
    for key in keys:
        try:
            result = result[key]
        except (KeyError, IndexError, TypeError):
            return default
    return result

