import random

def number_guessing_game():
    secret = random.randint(1, 100)
    attempts = 0

    print('Đoán số từ 1-100!')

    while True:
        try:
            guess = int(input('Nhập số: '))
            attempts += 1

            if guess < secret:
                print('Lớn hơn!')
            elif guess > secret:
                print('Nhỏ hơn!')
            else:
                print(f'Chúc mừng! Đoán đúng sau {attempts} lần!')
                break
        except ValueError:
            print('Vui lòng nhập số!')

def rock_paper_scissors():
    choices = ['kéo', 'búa', 'bao']
    wins = {'kéo': 'bao', 'búa': 'kéo', 'bao': 'búa'}

    computer = random.choice(choices)
    player = input('Chọn (kéo/búa/bao): ').lower()

    print(f'Máy chọn: {computer}')

    if player == computer:
        print('Hòa!')
    elif wins.get(player) == computer:
        print('Bạn thắng!')
    else:
        print('Máy thắng!')

import json
import os

TODO_FILE = 'todos.json'

def load_todos():
    if os.path.exists(TODO_FILE):
        with open(TODO_FILE, 'r') as f:
            return json.load(f)
    return []

def save_todos(todos):
    with open(TODO_FILE, 'w') as f:
        json.dump(todos, f, indent=2)

def add_todo(text):
    todos = load_todos()
    todos.append({'text': text, 'done': False})
    save_todos(todos)
    print(f'Added: {text}')

def list_todos():
    todos = load_todos()
    for i, todo in enumerate(todos, 1):
        status = '[x]' if todo['done'] else '[ ]'
        print(f'{i}. {status} {todo["text"]}')

def complete_todo(index):
    todos = load_todos()
    if 0 < index <= len(todos):
        todos[index-1]['done'] = True
        save_todos(todos)
        print('Marked as done!')

def delete_todo(index):
    todos = load_todos()
    if 0 < index <= len(todos):
        removed = todos.pop(index-1)
        save_todos(todos)
        print(f'Deleted: {removed["text"]}')

import tkinter as tk

class Calculator:
    def __init__(self):
        self.window = tk.Tk()
        self.window.title('Calculator')
        self.expression = ''

        # Display
        self.display = tk.Entry(self.window, width=20, font=('Arial', 20))
        self.display.grid(row=0, column=0, columnspan=4)

        # Buttons
        buttons = [
            '7', '8', '9', '/',
            '4', '5', '6', '*',
            '1', '2', '3', '-',
            'C', '0', '=', '+'
        ]

        row, col = 1, 0
        for btn in buttons:
            tk.Button(self.window, text=btn, width=5, height=2,
                     command=lambda b=btn: self.click(b)).grid(row=row, column=col)
            col += 1
            if col > 3:
                col = 0
                row += 1

    def click(self, btn):
        if btn == 'C':
            self.expression = ''
        elif btn == '=':
            try:
                self.expression = str(eval(self.expression))
            except:
                self.expression = 'Error'
        else:
            self.expression += btn
        self.display.delete(0, tk.END)
        self.display.insert(0, self.expression)

    def run(self):
        self.window.mainloop()

